{% set raw_ri = frappe.form_dict.get('return_items', '[]') %}
{% set return_items = json.loads(raw_ri) %}
{% set n_items = return_items | length %}
{% set DEDUCTION_PCT = 12 %}
{% set max_rows = 9 if n_items <= 9 else 34 %}

{% set patient_doc = frappe.get_doc('Patient', {'patient_name': doc.patient_name}) %}
{% set doctor_doc = frappe.get_doc('Healthcare Practitioner', doc.healthcare_practitioner) %}

{%- set ns = namespace(total_gross=0.0, total_deduct=0.0, total_net=0.0, total_qty=0.0) -%}
{%- for ri in return_items -%}
  {%- set med = doc.medicines | selectattr('item_code', 'equalto', ri.item_code) | selectattr('batch', 'equalto', ri.batch) | first -%}
  {%- if med -%}
    {%- set gross = (med.amount / med.qty) * ri.qty -%}
    {%- set ns.total_gross = ns.total_gross + gross -%}
    {%- set ns.total_deduct = ns.total_deduct + gross * (DEDUCTION_PCT / 100) -%}
    {%- set ns.total_net = ns.total_net + gross * (1 - DEDUCTION_PCT / 100) -%}
    {%- set ns.total_qty = ns.total_qty + ri.qty -%}
  {%- endif -%}
{%- endfor -%}

{% if n_items <= 9 %}
